const input = $input.first().json;
const body = input.body || input;

// Detectar origem da mensagem
let source = null;

// Telegram: { update_id: N, message: { ... } }
if (body.message && body.message.from && body.message.from.id) {
  source = 'TELEGRAM';
}
// WhatsApp (WAHA): { payload: { from: '...', ... } }
else if (body.payload && body.payload.from) {
  source = 'WHATSAPP';
}

if (!source) return [];

return [{ json: { source, raw: body } }];

const raw = $input.first().json.raw;
const msg = raw.message || {};
const text = (msg.text || '').trim();
if (!text) return [];
const chatId = String(msg.chat?.id || '');
const nome = msg.from?.first_name || 'chefe';
const phone = String(msg.from?.id || '');
const canal = 'telegram';
const whatsapp_id = phone + '@' + canal;

return [{ json: { phone, canal, whatsapp_id, chatId, text, nome, source: 'TELEGRAM' } }];

const raw = $input.first().json.raw;
const payload = raw.payload || {};
const from = payload.from || '';
const text = (payload.body || payload.text || '').trim();
if (!text) return [];

const phone = from.replace(/@s\.whatsapp\.net$/i, '').replace(/@c\.us$/i, '').replace(/@lid$/i, '').replace(/\D/g, '');
const whatsapp_id = phone + '@c.us';
const chatId = payload._data?.key?.remoteJidAlt || from;
const nome = (payload._data?.pushName || 'chefe').split(' ')[0];
const canal = 'whatsapp';

return [{ json: { phone, canal, whatsapp_id, chatId, text, nome, source: 'WHATSAPP' } }];

// Mesclar saídas de ambos os parsers
const items = $input.all();
return items.map(i => ({ json: i.json }));

// UNIFIED: Aceita tanto Telegram quanto WhatsApp (ya parseados)
const input = $input.first().json;
const text = (input.text || '').trim();
const phone = input.phone;
const whatsapp_id = input.whatsapp_id;
const chatId = input.chatId;
const nome = input.nome;
const source = input.source; // TELEGRAM|WHATSAPP
const canal = input.canal;

if (!text || !phone) return [];

// RATE LIMIT: 3 segundos entre mensagens do mesmo usuário (REQ 2)
const now = Date.now();
const globalState = $getWorkflowStaticData('global');
const lastMsgKey = 'last_msg_' + whatsapp_id;
const lastTime = globalState[lastMsgKey] || 0;
if (now - lastTime < 3000) {
  return [{ json: { bloqueado_rate_limit: true, tempo_restante_s: Math.ceil((3000 - (now - lastTime)) / 1000) } }];
}
globalState[lastMsgKey] = now;

// Limpar entradas antigas (>1h) para não acumular memória
for (const key of Object.keys(globalState)) {
  if (key.startsWith('last_msg_') && now - globalState[key] > 3600000) {
    delete globalState[key];
  }
}

// Verificar duplicata pendente
const dupKey = 'dup_' + whatsapp_id;
const dupPendente = globalState[dupKey] || null;
let resposta_duplicata = '';

if (dupPendente) {
  const resp = text.toLowerCase();
  if (resp.includes('sim') || resp.includes('criar')) {
    resposta_duplicata = 'CRIAR';
  } else if (resp.includes('editar') || resp.includes('mudar')) {
    resposta_duplicata = 'EDITAR';
  } else if (resp.includes('cancelar') || resp.includes('nao') || resp.includes('não')) {
    resposta_duplicata = 'CANCELAR';
  } else {
    resposta_duplicata = 'INVALIDO';
  }
}

return [{ json: { phone, canal, whatsapp_id, chatId, text, nome, dupPendente, resposta_duplicata, bloqueado_rate_limit: false, source } }];

const data = $input.first().json;
const globalState = $getWorkflowStaticData('global');
const dupKey = 'dup_' + data.whatsapp_id;
const dupData = JSON.parse(globalState[dupKey] || '{}');
delete globalState[dupKey];

const nome = data.nome;
const chatId = data.chatId;
const resp = data.resposta_duplicata;

if (resp === 'CRIAR') {
  return [{ json: { ...data, ...dupData, acao_dup: 'CRIAR' } }];
} else if (resp === 'EDITAR') {
  return [{ json: { ...data, ...dupData, acao_dup: 'EDITAR' } }];
} else if (resp === 'CANCELAR') {
  return [{ json: { chatId, mensagem: `Ok ${nome}, nao criei. Menos bagunca na lista ☕`, acao_dup: 'CANCELAR' } }];
} else {
  return [{ json: { chatId, mensagem: `${nome}, responde 'sim criar', 'editar' ou 'cancelar' 👀`, acao_dup: 'INVALIDO' } }];
}

const db = $input.first().json;
const nome = $('Filtrar Mensagem').first().json.nome || 'chefe';
