Tamo junto nas pendencias 👀`;
return [{ json: { chatId, mensagem: msg, source: $('Filtrar Mensagem').first().json.source } }];

const filtro = $('Preparar Fluxo').first().json;
const dbResult = $input.first().json;
const temPendencia = dbResult.tarefa_pendente_id ? true : false;
return [{ json: { ...filtro, temPendencia, tarefa_pendente_id: dbResult.tarefa_pendente_id || null, tarefa_pendente_titulo: dbResult.tarefa_pendente_titulo || null } }];

const text = $input.first().json.text;
const hoje = new Date().toISOString().split('T')[0];
const prompt = 'O usuario informou uma data para uma tarefa pendente. Extraia a data e retorne APENAS JSON puro com campos: data (formato YYYY-MM-DD) e resposta (confirmacao na voz do Tarefildo). Hoje eh ' + hoje + '. Se disser amanha calcule. Se disser sexta calcule a proxima. Se nao conseguir retorne data vazio.';
return [{ json: { prompt, text } }];

const input = $input.first().json;
const state = $('Preparar Estado').first().json;
let data = ''; let resposta = '';
try { let raw = input.choices[0].message.content.trim(); raw = raw.replace(/```json/gi, '').replace(/```/g, '').trim(); const match = raw.match(/\{[\s\S]*\}/); if (match) raw = match[0]; const parsed = JSON.parse(raw); data = parsed.data || ''; resposta = parsed.resposta || ''; } catch(e) { data = ''; resposta = 'Nao entendi a data.'; }
return [{ json: { ...state, data_extraida: data, resposta_data: resposta } }];

const db = $input.first().json;
const state = $('Preparar Estado').first().json;
const nome = $('Filtrar Mensagem').first().json.nome || 'chefe';
const d = db.data_vencimento || ''; const titulo = db.titulo || state.tarefa_pendente_titulo;
let df = ''; if (d) { const p = d.split('T')[0].split('-'); df = `${p[2]}/${p[1]}/${p[0]}`; }
const msg = `Pronto ${nome}, '${titulo}' pro dia ${df}. Tamo junto 👀`;
return [{ json: { chatId: state.chatId, mensagem: msg } }];

const state = $('Preparar Estado').first().json;
const nome = $('Filtrar Mensagem').first().json.nome || 'chefe';
const msg = `${nome}, nao peguei a data. Me fala tipo 'dia 25' ou 'proxima sexta' 😬`;
return [{ json: { chatId: state.chatId, mensagem: msg } }];

const text = $input.first().json.text;
const nome = $input.first().json.nome || 'chefe';
const hoje = new Date().toISOString().split('T')[0];
const prompt = 'Voce eh o Tarefildo Silva das Pendencias, bot assistente de tarefas. Funcionario raiz, engracado, sarcastico. O usuario se chama ' + nome + '. Usa: bora resolver, ja era pra ontem, confia no Tarefildo. Emojis moderados. Seja curto. Responda APENAS JSON puro sem markdown contendo: intent (adicionar_tarefa ou listar_tarefas ou concluir_tarefa ou editar_tarefa ou excluir_tarefa ou adicionar_lembrete ou listar_lembretes ou busca_natural ou ajuda ou conversa), dados (titulo, titulo_atual, novo_titulo, descricao, data YYYY-MM-DD, nova_data YYYY-MM-DD, hora HH:MM, nova_hora HH:MM, id, consulta, periodo, status_filtro, termo), resposta (frase do Tarefildo). Para listar_tarefas extraia: periodo (hoje ou amanha ou semana ou proxima_semana ou tudo - use tudo se usuario nao especificou periodo). Para editar_tarefa use titulo_atual com o nome atual e nova_data ou nova_hora ou novo_titulo com o valor novo. Para excluir_tarefa use titulo com o nome da tarefa a remover. Para busca_natural quando usuario perguntar sobre tarefas passadas ou futuras ou buscar algo especifico use: consulta (texto da busca), periodo (hoje ou amanha ou ontem ou semana ou semana_passada ou proxima_semana ou mes ou mes_passado ou tudo), status_filtro (PENDENTE ou CONCLUIDA ou CANCELADA ou todos), termo (palavra-chave). Para detectar_duplicatas quando usuario perguntar sobre tarefas duplicadas ou repetidas. Para limpar_duplicatas quando usuario confirmar que quer remover duplicatas. Hoje eh ' + hoje + '. Datas relativas converta para YYYY-MM-DD.';
return [{ json: { prompt, text } }];

const text = $input.first().json.text.toLowerCase();
const state = $('Preparar Estado').first().json;
const prompt = $input.first().json.prompt;

const fallback = {
  intent: null,
  dados: {},
  resposta: null,
  fallback_attempt: false,
  prompt: prompt,
  text: $input.first().json.text
};

// Lista de tarefas
if (text.match(/\b(lista|minhas|tarefas|ver|show)\b/i)) {
  fallback.intent = 'listar_tarefas';
  fallback.fallback_attempt = true;
}
// Adicionar tarefa
else if (text.match(/^(tarefa|adiciona?|add)\b/i)) {
  const titulo = text.replace(/^(tarefa|adiciona?|add)\s*:?\s*/i, '').trim();
  if (titulo) {
    fallback.intent = 'adicionar_tarefa';
    fallback.dados = { titulo };
    fallback.fallback_attempt = true;
  }
}
// Ajuda / Comando
else if (text.match(/\b(ajuda|help|comando|o que|quais)\b/i)) {
  fallback.intent = 'ajuda';
  fallback.fallback_attempt = true;
}
// Concluir tarefa
else if (text.match(/\b(concluir|done|pronto|finalizei|fechei)\b/i)) {
  fallback.intent = 'conversa';
  fallback.resposta = 'Qual tarefa foi conclu\u00edda? Me manda o nome certinho.';
  fallback.fallback_attempt = true;
}

return [{ json: { ...fallback, phone: state.phone, chatId: state.chatId, whatsapp_id: state.whatsapp_id } }];

const input = $input.first().json;
const state = $('Preparar Estado').first().json;

// Se fallback_attempt está marcado, usar fallback (REQ 8)
if (input.fallback_attempt === true && input.intent) {
  if (!input.resposta) input.resposta = 'Tudo certo! 😊';
  if (!input.dados) input.dados = {};
  return [{ json: { ...input, phone: state.phone, chatId: state.chatId, whatsapp_id: state.whatsapp_id } }];
}

// Senão, processar resposta do DeepSeek
if (input.error || !input.choices) {
  return [{ json: { intent: 'conversa', dados: {}, resposta: 'Probleminha tecnico 😅', phone: state.phone, chatId: state.chatId, whatsapp_id: state.whatsapp_id } }];
}

let raw = input.choices[0].message.content.trim();
raw = raw.replace(/```json/gi, '').replace(/```/g, '').trim();
const jsonMatch = raw.match(/\{[\s\S]*\}/);
if (jsonMatch) raw = jsonMatch[0];
let parsed;
try { parsed = JSON.parse(raw); } catch(e) { parsed = { intent: 'conversa', dados: {}, resposta: raw.length < 300 ? raw : 'Nao entendi 🙏' }; }
if (parsed.intent === 'outro') parsed.intent = 'conversa';
if (!parsed.resposta) parsed.resposta = 'Tudo certo! 😊';
if (!parsed.dados) parsed.dados = {};
return [{ json: { ...parsed, phone: state.phone, chatId: state.chatId, whatsapp_id: state.whatsapp_id } }];

const item = $input.first().json;
let titulo = (item.dados?.titulo_atual || item.dados?.titulo || '').trim();
const whatsapp_id = (item.whatsapp_id || '').trim();

if (titulo.length > 500) titulo = titulo.substring(0, 500);
if (!whatsapp_id.match(/^\d+@(c\.us|telegram|s\.whatsapp\.net)$/)) {
  return [{ json: { ...item, sem_titulo: true, erro: 'ID invalido' } }];
}

if (!titulo) {
  const globalState = $getWorkflowStaticData('global');
  const lastTask = globalState['last_task_' + whatsapp_id];
  if (lastTask) {
    try { titulo = JSON.parse(lastTask).titulo || ''; } catch(e) {}
  }
}

if (!titulo) {
  return [{ json: { ...item, sem_titulo: true } }];
}

const stopWords = ['a','o','de','da','do','para','pra','pro','com','em','na','no','as','os','um','uma','e','ou','que','se','tarefa'];
const palavras = titulo.toLowerCase().split(/\s+/).filter(p => p.length > 1 && !stopWords.includes(p)).map(p => p.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'));
const busca = palavras.length > 0 ? palavras.join('|') : titulo.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
return [{ json: { ...item, busca_titulo: busca, busca_whatsapp_id: whatsapp_id, sem_titulo: false } }];

const items = $input.all();
const state = $('Parsear NLP').first().json;
const prepBusca = $('Preparar Busca Edição').first().json;
const nome = $('Filtrar Mensagem').first().json.nome || 'chefe';
const chatId = state.chatId;
const dados = state.dados || {};

if (prepBusca.sem_titulo) {
  return [{ json: { chatId, mensagem: `${nome}, qual tarefa quer editar? Me fala o nome.`, tarefa_id: '' } }];
}

const validos = items.filter(i => i.json?.id);

if (validos.length === 0) {
  return [{ json: { chatId, mensagem: `${nome}, nao achei essa tarefa. Me fala o nome certinho.`, tarefa_id: '' } }];
}

if (validos.length > 1) {
  const lista = validos.map((i, idx) => {
    let info = 'sem data';
    if (i.json.data_vencimento) { const p = i.json.data_vencimento.split('T')[0].split('-'); info = `${p[2]}/${p[1]}/${p[0]}`; }
    return `${idx+1}. ${i.json.titulo} — ${info}`;
  }).join('\n');
  return [{ json: { chatId, mensagem: `${nome}, achei mais de uma. Qual dessas?\n\n${lista}\n\nMe fala o nome completo.`, tarefa_id: '' } }];
}

const tarefa = validos[0].json;
const updates = [];
if (dados.nova_data) updates.push(`data_vencimento = '${dados.nova_data}'`);
if (dados.nova_hora) updates.push(`hora_vencimento = '${dados.nova_hora}'`);
if (dados.novo_titulo) updates.push(`titulo = '${dados.novo_titulo}'`);
updates.push(`atualizado_em = NOW()`);

return [{ json: { chatId, tarefa_id: tarefa.id, titulo: tarefa.titulo, updates: updates.join(', '), dados, nome } }];

const item = $input.first().json;
const dados = item.dados || {};
const sets = [];
const params = [];
let idx = 1;

if (dados.novo_titulo) { sets.push(`titulo = $${idx}`); params.push(dados.novo_titulo); idx++; }
if (dados.nova_data) { sets.push(`data_vencimento = $${idx}::date`); params.push(dados.nova_data); idx++; }
if (dados.nova_hora) { sets.push(`hora_vencimento = $${idx}::time`); params.push(dados.nova_hora); idx++; }
sets.push('atualizado_em = NOW()');

const whereIdx = idx;
const query = `UPDATE tarefas SET ${sets.join(', ')} WHERE id = $${whereIdx} RETURNING id, titulo, data_vencimento, hora_vencimento;`;
params.push(item.tarefa_id);

return [{ json: { query, queryParams: params.join(','), chatId: item.chatId, nome: item.nome } }];

const db = $input.first().json;
const nome = $('Filtrar Mensagem').first().json.nome || 'chefe';
const chatId = $('Parsear NLP').first().json.chatId;
let info = '';
if (db.data_vencimento) { const p = db.data_vencimento.split('T')[0].split('-'); info = `${p[2]}/${p[1]}/${p[0]}`; }
if (db.hora_vencimento) info += ` as ${db.hora_vencimento.substring(0, 5)}`;
const msg = `Pronto ${nome}, '${db.titulo}' atualizada${info ? ' pro dia ' + info : ''}. Confia no Tarefildo ☕`;
return [{ json: { chatId, mensagem: msg } }];

const item = $input.first().json;
let titulo = (item.dados?.titulo || item.dados?.titulo_atual || '').trim();
const whatsapp_id = (item.whatsapp_id || '').trim();

if (titulo.length > 500) titulo = titulo.substring(0, 500);
if (!whatsapp_id.match(/^\d+@(c\.us|telegram|s\.whatsapp\.net)$/)) {
  return [{ json: { ...item, sem_titulo: true, erro: 'ID invalido' } }];
}

if (!titulo) {
  const globalState = $getWorkflowStaticData('global');
  const lastTask = globalState['last_task_' + whatsapp_id];
  if (lastTask) {
    try { titulo = JSON.parse(lastTask).titulo || ''; } catch(e) {}
  }
}

if (!titulo) {
  return [{ json: { ...item, sem_titulo: true } }];
}

