const palavras = titulo.toLowerCase().split(/\s+/).filter(p => p.length > 1 && !stopWords.includes(p)).map(p => p.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'));
const busca = palavras.length > 0 ? palavras.join('|') : titulo.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
return [{ json: { ...item, busca_titulo: busca, busca_whatsapp_id: whatsapp_id, sem_titulo: false } }];

const items = $input.all();
const state = $('Parsear NLP').first().json;
const prepBusca = $('Preparar Busca Exclusão').first().json;
const nome = $('Filtrar Mensagem').first().json.nome || 'chefe';
const chatId = state.chatId;

if (prepBusca.sem_titulo) {
  return [{ json: { chatId, mensagem: `${nome}, qual tarefa quer excluir? Me fala o nome.`, tarefa_id: '' } }];
}

const validos = items.filter(i => i.json?.id);

if (validos.length === 0) {
  return [{ json: { chatId, mensagem: `${nome}, nao achei essa tarefa pra excluir.`, tarefa_id: '' } }];
}

if (validos.length > 1) {
  const lista = validos.map((i, idx) => {
    let info = 'sem data';
    if (i.json.data_vencimento) { const p = i.json.data_vencimento.split('T')[0].split('-'); info = `${p[2]}/${p[1]}/${p[0]}`; }
    return `${idx+1}. ${i.json.titulo} — ${info}`;
  }).join('\n');
